import React, { useState } from 'react';
import { View, StyleSheet, TouchableOpacity, Animated } from 'react-native';
import { Ionicons } from '@expo/vector-icons';
import * as Haptics from 'expo-haptics';
import colors from '../styles/colors';

const InteractiveRating = ({ initialRating = 0, onRatingSelect, size = 40, color = '#F59E0B' }) => {
  const [rating, setRating] = useState(initialRating);
  const [animations] = useState([
    new Animated.Value(1),
    new Animated.Value(1),
    new Animated.Value(1),
    new Animated.Value(1),
    new Animated.Value(1),
  ]);

  const handlePress = (index) => {
    const newRating = index + 1;
    setRating(newRating);
    onRatingSelect && onRatingSelect(newRating);
    Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Medium);

    // Animate the selected star
    Animated.sequence([
      Animated.timing(animations[index], { toValue: 1.4, duration: 150, useNativeDriver: true }),
      Animated.spring(animations[index], { toValue: 1, friction: 3, tension: 40, useNativeDriver: true })
    ]).start();
  };

  return (
    <View style={styles.container}>
      {[0, 1, 2, 3, 4].map((index) => (
        <Animated.View key={index} style={{ transform: [{ scale: animations[index] }] }}>
          <TouchableOpacity
            onPress={() => handlePress(index)}
            activeOpacity={0.7}
            style={styles.starWrapper}
          >
            <Ionicons
              name={index < rating ? "star" : "star-outline"}
              size={size}
              color={index < rating ? color : '#CBD5E1'}
            />
          </TouchableOpacity>
        </Animated.View>
      ))}
    </View>
  );
};

const styles = StyleSheet.create({
  container: {
    flexDirection: 'row',
    justifyContent: 'center',
    alignItems: 'center',
    marginVertical: 15,
  },
  starWrapper: {
    marginHorizontal: 6,
  },
});

export default InteractiveRating;

import React, { useState, useEffect, useRef } from 'react';
import { 
  View, Text, StyleSheet, Modal, TextInput, 
  TouchableOpacity, ActivityIndicator, KeyboardAvoidingView, Platform 
} from 'react-native';
import { Ionicons } from '@expo/vector-icons';
import { useDispatch, useSelector } from 'react-redux';
import Toast from 'react-native-toast-message';
import colors from '../styles/colors';
import leadService from '../services/leadService';
import { setLeadCaptured } from '../store/authSlice';

const LeadGatekeeper = ({ visible, onClose, onSuccess, category }) => {
  const dispatch = useDispatch();
  const { isAuthenticated, user, temporaryLeadInfo } = useSelector(state => state.auth);
  const [name, setName] = useState('');
  const [phone, setPhone] = useState('');
  const [loading, setLoading] = useState(false);
  const phoneRef = useRef(null);

  useEffect(() => {
    if (visible) {
      if (isAuthenticated && user) {
        setName(user.name || '');
        setPhone(user.phone || '');
      } else if (temporaryLeadInfo) {
        setName(temporaryLeadInfo.name || '');
        setPhone(temporaryLeadInfo.phone || '');
      }
    }
  }, [visible, isAuthenticated, user, temporaryLeadInfo]);

  const handleSubmit = async () => {
    if (!name.trim() || !phone.trim()) {
      Toast.show({
        type: 'error',
        text1: 'Required Info',
        text2: 'Please provide both name and phone number.'
      });
      return;
    }

    setLoading(true);
    try {
      // Just limit this to taking info for tracking as requested by the user.
      // We no longer trigger a backend API lead creation here because guest users
      // get a 401 error since /leads is now protected. Wait until they actually book.
      dispatch(setLeadCaptured({ name, phone }));
      onSuccess();
    } catch (error) {
      Toast.show({
        type: 'error',
        text1: 'Submission Failed',
        text2: 'Could not capture info. Please try again.'
      });
    } finally {
      setLoading(false);
    }
  };


  return (
    <Modal
      visible={visible}
      transparent
      animationType="fade"
      onRequestClose={onClose}
    >
      <View style={styles.overlay}>
        <KeyboardAvoidingView 
          behavior={Platform.OS === 'ios' ? 'padding' : 'height'}
          style={styles.container}
        >
          <View style={styles.card}>
            <View style={styles.header}>
              <View>
                <Text style={styles.title}>Quick Inquiry</Text>
                <Text style={styles.subtitle}>Get the best {category?.name || 'service'} quotes</Text>
              </View>
              <TouchableOpacity onPress={onClose} style={styles.closeBtn}>
                <Ionicons name="close" size={24} color="#1F2937" />
              </TouchableOpacity>
            </View>

            <View style={styles.form}>
              <View style={styles.inputWrapper}>
                <Ionicons name="person-outline" size={20} color="#6B7280" style={styles.inputIcon} />
                <TextInput
                  style={styles.input}
                  placeholder="Your Full Name"
                  value={name}
                  onChangeText={setName}
                  placeholderTextColor="#9CA3AF"
                  autoCapitalize="words"
                  returnKeyType="next"
                  onSubmitEditing={() => phoneRef.current?.focus()}
                  blurOnSubmit={false}
                />
              </View>

              <View style={styles.inputWrapper}>
                <Ionicons name="call-outline" size={20} color="#6B7280" style={styles.inputIcon} />
                <TextInput
                  ref={phoneRef}
                  style={styles.input}
                  placeholder="Phone Number"
                  value={phone}
                  onChangeText={setPhone}
                  keyboardType="phone-pad"
                  placeholderTextColor="#9CA3AF"
                  returnKeyType="done"
                  onSubmitEditing={handleSubmit}
                />
              </View>

              <TouchableOpacity 
                style={[styles.submitBtn, loading && styles.disabledBtn]} 
                onPress={handleSubmit}
                disabled={loading}
              >
                {loading ? (
                  <ActivityIndicator color="#FFF" />
                ) : (
                  <>
                    <Text style={styles.submitText}>Continue to Results</Text>
                    <Ionicons name="arrow-forward" size={20} color="#FFF" />
                  </>
                )}
              </TouchableOpacity>

              <Text style={styles.disclaimer}>
                By continuing, you agree to share these details with local {category?.name || 'service'} providers.
              </Text>
            </View>
          </View>
        </KeyboardAvoidingView>
      </View>
    </Modal>
  );
};

const styles = StyleSheet.create({
