        fetchAdminData(true);

        const newLog = {
            id: `biz-${Date.now()}`,
            action: `Business Registered: "${data.name}"`,
            time: 'Just now',
            icon: 'business',
            color: '#10B981'
        };
        setRecentActivity(prev => [newLog, ...prev.slice(0, 5)]);
