        const newLog = {
            id: `log-${Date.now()}`,
            action: data.action,
            time: 'Just now',
            icon: 'pulse',
            color: '#6B7280'
        };
        setRecentActivity(prev => [newLog, ...prev.slice(0, 5)]);
    });

    return () => {
      // socketService.disconnect();
