            {item.unread > 0 && (
              <LinearGradient colors={[colors.primary, '#E65C00']} start={{x:0, y:0}} end={{x:1, y:1}} style={styles.unreadBadge}>
                <Text style={styles.unreadCount}>{item.unread}</Text>
