            </LinearGradient>
          </View>
        </AnimatedFadeIn>

        {/* ─ Categories ─ */}
        <AnimatedFadeIn delay={300}>
          <SectionHeader
            title="Browse by Category"
            onSeeAll={() => navigation.navigate('CategoriesTab')}
          />
          <ScrollView 
            horizontal 
            showsHorizontalScrollIndicator={false} 
            contentContainerStyle={styles.categoriesScroll}
