                  <Text style={styles.statLabel}>Saved</Text>
                </TouchableOpacity>
                <View style={styles.statDivider} />
                <TouchableOpacity style={styles.statItem} onPress={() => Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light)}>
