  View, Text, StyleSheet, FlatList, ScrollView, TouchableOpacity,
  Image, Modal, Pressable, Animated, useWindowDimensions, Linking,
  ActivityIndicator, Platform
} from 'react-native';
import { useSelector } from 'react-redux';
