// ─── Main Screen ──────────────────────────────────────────────────────────────

const RequestsScreen = ({ navigation }) => {
  const { width } = useWindowDimensions();
  const { user, isAuthenticated } = useSelector(state => state.auth);

  const [activeFilter, setActiveFilter] = useState('All');
  const [requests, setRequests] = useState([]);
  const [loading, setLoading] = useState(true);
  const [refreshing, setRefreshing] = useState(false);
  const [selectedBooking, setSelectedBooking] = useState(null);
  const [modalVisible, setModalVisible] = useState(false);

  const fetchRequests = React.useCallback(async (isSilent = false) => {
    if (!isSilent) setLoading(true);
    try {
      if (!user) return;
      const res = await leadService.getUserLeads();
      setRequests(res.data || []);
    } catch (e) {
      console.log('Fetch requests err:', e);
      if (!isSilent) Toast.show({ type: 'error', text1: 'Network Error', text2: 'Could not sync your requests.' });
    } finally {
      setLoading(false);
      setRefreshing(false);
    }
  }, [user]);

  useFocusEffect(
    React.useCallback(() => {
      if (isAuthenticated) {
        fetchRequests();
      } else {
        setLoading(false);
        setRequests([]);
      }
    }, [isAuthenticated, fetchRequests])
  );

  React.useEffect(() => {
    if (user?.id) {
        socketService.connect();
        socketService.joinRoom(user.id.toString());

        socketService.socket?.on('booking_status_updated', (data) => {
            Haptics.notificationAsync(Haptics.NotificationFeedbackType.Success);
            Toast.show({
                type: 'info',
                text1: 'Booking Update',
                text2: `A booking status has been updated to ${data.newStatus}.`
            });
            fetchRequests(true); // Silent refresh
        });
    }
  }, [user, fetchRequests]);

  const filtered = activeFilter === 'All' 
    ? (requests || [])
    : (requests || []).filter(r => r.status?.toLowerCase() === activeFilter.toLowerCase());

  const counts = FILTERS.reduce((acc, f) => {
    acc[f] = f === 'All' ? (requests?.length || 0) : (requests || []).filter(r => r.status?.toLowerCase() === f.toLowerCase()).length;
    return acc;
  }, {});

  const handleCardPress = (item) => {
    setSelectedBooking(item);
    setModalVisible(true);
  };

  const handleConfirm = async (id, paymentMode) => {
    Haptics.notificationAsync(Haptics.NotificationFeedbackType.Success);
    try {
      await leadService.updateLeadStatus(id, 'Completed');
      setRequests(prev =>
        prev.map(r => r.id === id 
          ? { 
              ...r, 
              status: 'Completed', 
              paymentStatus: paymentMode === 'later' ? 'Pay After Service' : 'Paid', 
              payment_method: PAYMENT_METHODS.find(m => m.id === paymentMode)?.label 
            }
          : r)
      );
      Toast.show({ type: 'success', text1: 'Booking Confirmed!', text2: 'Your service has been scheduled.' });
    } catch (e) {
      Toast.show({ type: 'error', text1: 'Update Failed', text2: 'Could not sync with server.' });
    }
  };

  const handleCancel = async (id) => {
    Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Medium);
    try {
      await leadService.updateLeadStatus(id, 'Cancelled');
      setRequests(prev => prev.map(r => r.id === id ? { ...r, status: 'Cancelled' } : r));
      Toast.show({ type: 'info', text1: 'Request Cancelled', text2: 'Your request has been cancelled.' });
    } catch (e) {
      Toast.show({ type: 'error', text1: 'Cancel Failed', text2: 'Could not sync with server.' });
    }
  };

  return (
    <SafeAreaView style={[globalStyles.container, styles.container]} edges={['top']}>
      {/* Header */}
      <View style={styles.header}>
        <TouchableOpacity 
          onPress={() => {
            Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
            navigation.openDrawer();
          }} 
          style={styles.menuBtn}
        >
          <Ionicons name="menu" size={26} color={colors.primary} />
        </TouchableOpacity>
        <View style={{ alignItems: 'center' }}>
          <Text style={styles.headerTitle}>My Requests</Text>
          <View style={styles.headerSubBadge}>
            <View style={styles.pulseDot} />
            <Text style={styles.headerSub}>{requests.length} total</Text>
          </View>
        </View>
        <TouchableOpacity 
          style={styles.notifBtn}
          onPress={() => Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light)}
        >
          <Ionicons name="notifications-outline" size={22} color="#374151" />
        </TouchableOpacity>
      </View>

      {/* Stats Row */}
      <View style={styles.statsRow}>
        {[
          { label: 'Active', count: requests.filter(r => r.status === 'Accepted' || r.status === 'Pending').length, color: '#F59E0B' },
          { label: 'Completed', count: requests.filter(r => r.status === 'Completed').length, color: '#10B981' },
          { label: 'Cancelled', count: requests.filter(r => r.status === 'Cancelled').length, color: '#EF4444' },
        ].map(s => (
          <View key={s.label} style={styles.statCard}>
            <Text style={[styles.statCount, { color: s.color }]}>{s.count}</Text>
            <Text style={styles.statLabel}>{s.label}</Text>
          </View>
        ))}
      </View>

      {/* Filter Tabs */}
      <ScrollView
        horizontal
        showsHorizontalScrollIndicator={false}
        style={styles.filterScroll}
        contentContainerStyle={styles.filterContent}
      >
        {FILTERS.map(f => {
          const active = activeFilter === f;
          return (
            <TouchableOpacity
              key={f}
              style={[styles.filterChip, active && styles.filterChipActive]}
              onPress={() => {
                Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
                setActiveFilter(f);
              }}
            >
              <Text style={[styles.filterText, active && styles.filterTextActive]}>{f}</Text>
              {counts[f] > 0 && (
                <View style={[styles.filterCount, active && styles.filterCountActive]}>
                  <Text style={[styles.filterCountText, active && { color: colors.primary }]}>{counts[f]}</Text>
                </View>
              )}
            </TouchableOpacity>
          );
        })}
      </ScrollView>

      {/* List */}
      <FlatList
        data={filtered}
        keyExtractor={item => item.id}
        renderItem={({ item }) => <RequestCard item={item} onPress={handleCardPress} />}
        contentContainerStyle={styles.list}
        showsVerticalScrollIndicator={false}
        ListEmptyComponent={
          <View style={styles.empty}>
            <Ionicons name="document-text-outline" size={72} color="#E5E7EB" />
            <Text style={styles.emptyTitle}>No Requests</Text>
            <Text style={styles.emptyDesc}>
              {activeFilter === 'All' ? 'Book a service to see your requests here.' : `No ${activeFilter} requests found.`}
            </Text>
          </View>
        }
      />

      {/* Booking Modal */}
      <BookingModal
        item={selectedBooking}
        visible={modalVisible}
        onClose={() => setModalVisible(false)}
        onConfirm={handleConfirm}
        onCancel={handleCancel}
      />
    </SafeAreaView>
  );
};

